---
*Generiert durch ECC Drift Detection v1.0.0*
"@

    Set-Content -Path $reportFile -Value $report -Encoding UTF8
    Write-DriftLog -Level "SUCCESS" -Message "Report gespeichert: $reportFile"

    return $reportFile
}

# ═══════════════════════════════════════════════════════════════
# HAUPTLOGIK
